webMI.proxy({"":[function(webMI,window,document,self){webMI.data.read([
	"HEOS_STD/$dev$.Integers.SW Major release | HwSw_Chk.SwVerX_msk",	
	"HEOS_STD/$dev$.Integers.SW Minor release | HwSw_Chk.SwVerY_msk"],
	function(e){
		var SW_Major = e[0].value;
		var SW_Minor = e[1].value;
		var id = "id_166";
		if (Number(SW_Major) >= 2 && Number(SW_Minor) >= 1)
			webMI.gfx.setVisible(id, false);
		else
			webMI.gfx.setVisible(id, true);
	}
);

webMI.addEvent("id_121", "click", function(e) {
