	webMI.gfx.setMoveY(id, webMI.translate(status, true, false, 0 , 0));
	if(status)
	{	// set green background color
		webMI.gfx.setFill("bckg_area",c_on);
	}
	else
	{
		// set grey background color
		webMI.gfx.setFill("bckg_area",c_off);
	}
