			array_polygon.push(eval(array_1[i]));
		}	

	var fill_opacity = 	webMI.query["fillOpacity"] + "%";
	var stroke_opacity = webMI.query["strokeOpacity"] + "%";

	//draw the envelope polygon
		webMI.gfx.addPolygon({
