			fillOpacity : fill_opacity,
			points: array_polygon,
			Stroke: webMI.query["strokeColor"],
			StrokeWidth: webMI.query["strokeWidth"],
			StrokeOpacity: stroke_opacity,    
		}, "id_envelope");


	//draw and arrange the labels

	for(i=0; i<x_coordinates.length; i++){
//====================================================================================//
//-------------------check if the point is inside the top left box--------------------//
//====================================================================================//

			if(x_coordinates_tra[i] <= width/2 && y_coordinates_tra[i] <= heigth/2){
				var a = x_coordinates_tra[i].toString();
				var b = y_coordinates_tra[i].toString();
