//---------------------check if the point is inside top right box---------------------//
//====================================================================================//		

			else if(x_coordinates_tra[i] >= width/2 && y_coordinates_tra[i] <= heigth/2){
				var x_offset = Math.abs(x_coordinates_tra[i]-width/2)* (x_offset_mtpl+0.1);
				var y_offset = Math.abs(y_coordinates_tra[i]-heigth/2)* (y_offset_mtpl+0.05);
					webMI.gfx.addText({
							x: x_offset + width/2,
