			else if(x_coordinates_tra[i] >= width/2 && y_coordinates_tra[i] >= heigth/2){
				var a = x_coordinates_tra[i].toString();
				var b = y_coordinates_tra[i].toString();
				var x_offset = Math.abs(x_coordinates_tra[i]-width/2)* (x_offset_mtpl+0.1);
