function point(x,y){
	this.x=x;
	this.y=y;
}

function calculate_min(values){
	return Math.min.apply(null, values);
}

function calculate_max(values){
	return Math.max.apply(null, values);
}

/** Check if the value comes from the server are reliable */
function isEmptyOrNull(array) {    
    return (array.lastIndexOf(null) == -1)? false :true ;  
}

/** Set all array elament to null */
function SetToNull(array) {
    for (var i = 0; i < array.length; i++) {
        array[i] = null;    
    }
}

